head.b:skin:
/*
-----------------------------------------------
Theme Name: Ayman IT Service Pro
Author: Ayman IT
Version: 2.0
-----------------------------------------------
*/

/* Variable definitions
====================
<Variable name="primary" description="Primary Color" type="color" default="#2563eb" value="#2563eb"/>
<Variable name="accent" description="Accent Color" type="color" default="#06b6d4" value="#06b6d4"/>
<Variable name="whatsapp" description="WhatsApp Color" type="color" default="#25d366" value="#25d366"/>
<Variable name="bg" description="Background" type="color" default="#ffffff" value="#ffffff"/>
<Variable name="text" description="Text Color" type="color" default="#0f172a" value="#0f172a"/>
<Variable name="muted" description="Muted Text" type="color" default="#64748b" value="#64748b"/>
<Variable name="border" description="Border Color" type="color" default="#e2e8f0" value="#e2e8f0"/>
<Variable name="body.font" description="Body Font" type="font" default="normal normal 15px Inter, sans-serif" value="normal normal 15px Inter, sans-serif"/>
*/

*{margin:0;padding:0;box-sizing:border-box}
html{scroll-behavior:smooth}
body{font-family:Inter,system-ui,sans-serif;color:#0f172a;background:#fff;line-height:1.6;font-size:15px}
body.dark{background:#0f172a;color:#e2e8f0}
img{max-width:100%;height:auto;display:block}
a{color:inherit;text-decoration:none}
.container{max-width:1200px;margin:0 auto;padding:0 16px}

/* News Ticker - BOTTOM OF SCREEN */
.news-ticker{bottom:0;left:0;right:0;background:linear-gradient(90deg,#dc2626,#ef4444);color:#fff;padding:8px 0;overflow:hidden;position:fixed;z-index:1000;font-size:14px;box-shadow:0 -2px 10px rgba(0,0,0,.1)}
.news-ticker-wrap{display:flex;align-items:center;gap:12px}
.news-ticker-label{background:#fff;color:#dc2626;font-weight:700;padding:4px 12px;border-radius:4px;white-space:nowrap;flex-shrink:0}
.news-ticker-content{flex:1;overflow:hidden;white-space:nowrap}
.news-ticker-track{display:inline-block;padding-left:100%;animation:tickerScroll 30s linear infinite}
.news-ticker-track a{color:#fff;margin-right:60px;display:inline-block;text-decoration:none}
.news-ticker-track a:hover{text-decoration:underline}
@keyframes tickerScroll{0%{transform:translateX(0)}100%{transform:translateX(-100%)}}

/* Header */
.top-bar{background:#0f172a;color:#fff;padding:8px 0;font-size:13px}
.top-bar-flex{display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:10px}
.top-info{display:flex;gap:18px;flex-wrap:wrap}
.top-socials a{margin-left:10px;opacity:.8}
.top-socials a:hover{opacity:1}

.header{background:#fff;box-shadow:0 2px 10px rgba(0,0,0,.06);position:sticky;top:0;z-index:100;transition:.3s}
body.dark .header{background:#1e293b}
.nav-wrap{display:flex;align-items:center;justify-content:space-between;padding:14px 0}
.logo{display:flex;align-items:center;gap:10px;font-weight:800;font-size:20px;color:#2563eb}
.logo img{height:42px;width:auto}
.nav-menu{display:flex;gap:6px;align-items:center}
.nav-menu a{padding:8px 14px;border-radius:6px;font-weight:500;transition:.2s}
.nav-menu a:hover{background:#eff6ff;color:#2563eb}
.header-cta{display:flex;gap:8px;align-items:center}
.btn{display:inline-flex;align-items:center;gap:6px;padding:9px 16px;border-radius:8px;font-weight:600;cursor:pointer;border:none;transition:.2s;font-size:14px}
.btn-primary{background:#2563eb;color:#fff}
.btn-primary:hover{background:#1d4ed8}
.btn-wa{background:#25d366;color:#fff}
.btn-outline{background:transparent;color:#2563eb;border:2px solid #2563eb}
.btn-outline:hover{background:#2563eb;color:#fff}
.menu-toggle{display:none;background:none;border:none;font-size:24px;cursor:pointer}

/* Hero Slider */
.hero-slider{position:relative;overflow:hidden;height:520px;background:#0f172a}
.hero-slide{position:absolute;inset:0;opacity:0;transition:opacity .8s;display:flex;align-items:center;background-size:cover;background-position:center}
.hero-slide.active{opacity:1;z-index:2}
.hero-slide::before{content:'';position:absolute;inset:0;background:linear-gradient(90deg,rgba(15,23,42,.85),rgba(15,23,42,.4))}
.hero-content{position:relative;z-index:2;max-width:640px;color:#fff;padding:0 20px}
.hero-content h1{font-size:48px;font-weight:800;margin-bottom:16px;line-height:1.15}
.hero-content p{font-size:18px;margin-bottom:24px;opacity:.95}
.hero-ctas{display:flex;gap:12px;flex-wrap:wrap}
.hero-ctas .btn{padding:13px 24px;font-size:15px}
.hero-arrow{position:absolute;top:50%;transform:translateY(-50%);background:rgba(255,255,255,.2);border:none;color:#fff;width:46px;height:46px;border-radius:50%;cursor:pointer;font-size:22px;z-index:5;backdrop-filter:blur(8px)}
.hero-arrow:hover{background:rgba(255,255,255,.35)}
.hero-prev{left:18px}.hero-next{right:18px}
.hero-dots{position:absolute;bottom:20px;left:50%;transform:translateX(-50%);display:flex;gap:8px;z-index:5}
.hero-dot{width:10px;height:10px;border-radius:50%;background:rgba(255,255,255,.5);border:none;cursor:pointer}
.hero-dot.active{background:#fff;width:28px;border-radius:5px}

/* Sections */
.section{padding:70px 0}
.section-head{text-align:center;margin-bottom:44px}
.section-head h2{font-size:36px;font-weight:800;margin-bottom:10px}
.section-head .text-gradient{background:linear-gradient(90deg,#2563eb,#06b6d4);-webkit-background-clip:text;background-clip:text;color:transparent}
.section-head p{color:#64748b;font-size:16px;max-width:600px;margin:0 auto}

/* Services Grid */
.services-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(260px,1fr));gap:22px}
.service-card{background:#fff;padding:28px;border-radius:14px;box-shadow:0 4px 18px rgba(0,0,0,.06);border:1px solid #e2e8f0;transition:.3s;cursor:pointer;position:relative;overflow:hidden}
body.dark .service-card{background:#1e293b;border-color:#334155}
.service-card:hover{transform:translateY(-6px);box-shadow:0 12px 32px rgba(37,99,235,.18);border-color:#2563eb}
.service-icon{width:58px;height:58px;border-radius:14px;background:linear-gradient(135deg,#2563eb,#06b6d4);color:#fff;display:flex;align-items:center;justify-content:center;font-size:26px;margin-bottom:18px}
.service-card h3{font-size:19px;font-weight:700;margin-bottom:10px}
.service-card p{color:#64748b;font-size:14px;margin-bottom:14px}
.service-link{color:#2563eb;font-weight:600;font-size:14px}

/* Service Modal */
.modal-overlay{position:fixed;inset:0;background:rgba(15,23,42,.7);display:none;align-items:center;justify-content:center;z-index:9999;padding:20px;backdrop-filter:blur(4px)}
.modal-overlay.active{display:flex;animation:fadeIn .25s}
.modal-box{background:#fff;border-radius:16px;max-width:560px;width:100%;max-height:90vh;overflow-y:auto;padding:30px;position:relative;animation:slideUp .3s}
body.dark .modal-box{background:#1e293b;color:#e2e8f0}
.modal-close{position:absolute;top:14px;right:14px;background:#f1f5f9;border:none;width:34px;height:34px;border-radius:50%;cursor:pointer;font-size:18px}
.modal-icon{width:64px;height:64px;border-radius:14px;background:linear-gradient(135deg,#2563eb,#06b6d4);color:#fff;display:flex;align-items:center;justify-content:center;font-size:30px;margin-bottom:16px}
.modal-box h3{font-size:24px;margin-bottom:12px}
.modal-box ul{margin:14px 0;padding-left:20px}
.modal-box ul li{margin-bottom:6px;color:#475569}
body.dark .modal-box ul li{color:#cbd5e1}
.modal-actions{display:flex;gap:10px;margin-top:18px;flex-wrap:wrap}
@keyframes fadeIn{from{opacity:0}to{opacity:1}}
@keyframes slideUp{from{transform:translateY(20px);opacity:0}to{transform:translateY(0);opacity:1}}

/* Photo / Video Gallery Slider */
.gallery-slider{position:relative;overflow:hidden;border-radius:14px}
.gallery-track{display:flex;transition:transform .5s ease}
.gallery-slide{min-width:33.333%;padding:0 8px;box-sizing:border-box}
.gallery-slide img,.gallery-slide video,.gallery-slide iframe{width:100%;height:240px;object-fit:cover;border-radius:12px;border:0}
.gal-arrow{position:absolute;top:50%;transform:translateY(-50%);background:#2563eb;color:#fff;border:none;width:42px;height:42px;border-radius:50%;cursor:pointer;font-size:20px;z-index:3}
.gal-prev{left:-6px}.gal-next{right:-6px}
@media(max-width:768px){.gallery-slide{min-width:100%}}

/* About */
.about-grid{display:grid;grid-template-columns:1fr 1fr;gap:50px;align-items:center}
.about-stats{display:grid;grid-template-columns:repeat(2,1fr);gap:18px;margin-top:24px}
.stat{background:#f8fafc;padding:20px;border-radius:12px;text-align:center}
body.dark .stat{background:#1e293b}
.stat-num{font-size:32px;font-weight:800;color:#2563eb}
@media(max-width:768px){.about-grid{grid-template-columns:1fr}}

/* Blog */
.blog-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(280px,1fr));gap:24px}
.blog-card{background:#fff;border-radius:14px;overflow:hidden;border:1px solid #e2e8f0;transition:.3s}
body.dark .blog-card{background:#1e293b;border-color:#334155}
.blog-card:hover{transform:translateY(-4px);box-shadow:0 10px 24px rgba(0,0,0,.08)}
.blog-card img{width:100%;height:200px;object-fit:cover}
.blog-body{padding:18px}
.blog-body h3{font-size:18px;margin-bottom:8px}
.blog-meta{font-size:12px;color:#64748b;margin-bottom:8px}

/* Sidebar (used on post & static pages) */
.content-with-sidebar{display:grid;grid-template-columns:1fr 320px;gap:32px}
@media(max-width:992px){.content-with-sidebar{grid-template-columns:1fr}}
.sidebar .widget{background:#fff;border:1px solid #e2e8f0;border-radius:12px;padding:18px;margin-bottom:18px}
body.dark .sidebar .widget{background:#1e293b;border-color:#334155}
.sidebar .widget h2,.sidebar .widget .title{font-size:16px;font-weight:700;margin-bottom:12px;padding-bottom:8px;border-bottom:2px solid #2563eb}

/* Post / Static Page */
.post-wrap{background:#fff;padding:30px;border-radius:14px;border:1px solid #e2e8f0}
body.dark .post-wrap{background:#1e293b;border-color:#334155}
.post-title{font-size:32px;font-weight:800;margin-bottom:12px;line-height:1.25}
.post-meta{display:flex;gap:14px;color:#64748b;font-size:13px;margin-bottom:18px;flex-wrap:wrap}
.post-meta span{display:flex;align-items:center;gap:5px}
.post-thumb{width:100%;max-height:420px;object-fit:cover;border-radius:12px;margin-bottom:18px}
.post-body{font-size:16px;line-height:1.8}
.post-body h2,.post-body h3{margin:20px 0 10px}
.post-body p{margin-bottom:14px}
.post-body img{border-radius:10px;margin:12px 0}
.post-body blockquote{border-left:4px solid #2563eb;padding:10px 16px;background:#eff6ff;margin:14px 0;border-radius:6px}
body.dark .post-body blockquote{background:#1e3a8a;color:#dbeafe}

.breadcrumb{font-size:13px;color:#64748b;margin-bottom:14px}
.breadcrumb a{color:#2563eb}

.share-bar{display:flex;gap:8px;margin:18px 0;flex-wrap:wrap}
.share-bar a{padding:8px 14px;border-radius:6px;color:#fff;font-size:13px;font-weight:600}
.share-fb{background:#1877f2}.share-tw{background:#1da1f2}.share-wa{background:#25d366}.share-tg{background:#0088cc}

.author-box{display:flex;gap:14px;background:#f8fafc;padding:16px;border-radius:12px;margin:20px 0;align-items:center}
body.dark .author-box{background:#0f172a}
.author-box img{width:60px;height:60px;border-radius:50%}

.related-posts{margin-top:30px}
.related-posts h3{font-size:20px;margin-bottom:14px;padding-bottom:8px;border-bottom:2px solid #2563eb}
.related-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(180px,1fr));gap:14px}
.related-item{display:block;background:#f8fafc;padding:10px;border-radius:8px;font-size:13px;font-weight:600}
body.dark .related-item{background:#0f172a}

.comments{margin-top:30px}

/* Newsletter */
.newsletter{background:linear-gradient(135deg,#2563eb,#06b6d4);padding:60px 0;color:#fff;text-align:center;border-radius:18px;margin:40px 0}
.newsletter h2{font-size:32px;margin-bottom:10px}
.newsletter-form{display:flex;gap:8px;max-width:480px;margin:20px auto 0;flex-wrap:wrap;justify-content:center}
.newsletter-form input{flex:1;min-width:200px;padding:13px 16px;border-radius:8px;border:none;font-size:15px}
.newsletter-form button{background:#0f172a;color:#fff;padding:13px 24px;border-radius:8px;border:none;font-weight:600;cursor:pointer}

/* Footer */
.footer{background:#0f172a;color:#cbd5e1;padding:50px 0 20px;margin-top:50px}
.footer-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(220px,1fr));gap:30px;margin-bottom:30px}
.footer h4{color:#fff;margin-bottom:14px;font-size:16px}
.footer a{color:#cbd5e1;display:block;padding:4px 0;font-size:14px}
.footer a:hover{color:#06b6d4}
.footer-bottom{border-top:1px solid #334155;padding-top:18px;text-align:center;font-size:13px}

/* Floating buttons */
.float-btn{position:fixed;right:18px;width:54px;height:54px;border-radius:50%;display:flex;align-items:center;justify-content:center;color:#fff;font-size:24px;box-shadow:0 6px 18px rgba(0,0,0,.25);z-index:99;cursor:pointer;border:none}
.float-wa{background:#25d366;bottom:90px}
.float-call{background:#2563eb;bottom:154px}
.float-top{background:#0f172a;bottom:26px;opacity:0;transition:.3s}
.float-top.show{opacity:1}

/* Chatbot */
.chatbot-widget{background:linear-gradient(135deg,#2563eb,#06b6d4);color:#fff;padding:18px;border-radius:14px}
.chatbot-widget h3{font-size:16px;margin-bottom:8px;color:#fff;border:none;padding:0}
.chatbot-toggle{background:#fff;color:#2563eb;width:100%;padding:10px;border-radius:8px;font-weight:700;margin-top:10px;border:none;cursor:pointer}
.chatbot-box{position:fixed;bottom:90px;right:90px;width:340px;max-width:calc(100vw - 40px);height:460px;background:#fff;border-radius:14px;box-shadow:0 20px 50px rgba(0,0,0,.25);display:none;flex-direction:column;z-index:200;overflow:hidden}
.chatbot-box.open{display:flex}
.chatbot-header{background:linear-gradient(135deg,#2563eb,#06b6d4);color:#fff;padding:14px;display:flex;justify-content:space-between;align-items:center}
.chatbot-header b{font-size:15px}
.chatbot-header button{background:none;border:none;color:#fff;font-size:20px;cursor:pointer}
.chatbot-msgs{flex:1;padding:14px;overflow-y:auto;background:#f8fafc}
.cb-msg{margin-bottom:10px;padding:9px 13px;border-radius:10px;font-size:14px;max-width:85%}
.cb-bot{background:#e0f2fe;color:#0c4a6e}
.cb-user{background:#2563eb;color:#fff;margin-left:auto}
.chatbot-input{display:flex;border-top:1px solid #e2e8f0}
.chatbot-input input{flex:1;padding:12px;border:none;outline:none;font-size:14px}
.chatbot-input button{background:#2563eb;color:#fff;border:none;padding:0 18px;cursor:pointer;font-weight:600}

/* Responsive */
@media(max-width:900px){
  .nav-menu{display:none;position:absolute;top:100%;left:0;right:0;background:#fff;flex-direction:column;padding:12px;box-shadow:0 4px 12px rgba(0,0,0,.1)}
  .nav-menu.open{display:flex}
  body.dark .nav-menu{background:#1e293b}
  .menu-toggle{display:block}
  .hero-content h1{font-size:32px}
  .hero-content p{font-size:15px}
  .hero-slider{height:440px}
  .section{padding:50px 0}
  .section-head h2{font-size:28px}
  .top-bar{display:none}
  /* Add bottom padding for fixed ticker */
  body{padding-bottom:45px}
}
/* Padding for fixed ticker on desktop */
body{padding-bottom:45px}

body.script:
//

// ===== SERVICES DATA =====
var SERVICES = [
  {icon:'🌐',title:'Online Services',desc:'Government & online form submission service.',price:'৳50 - ৳500',list:['NID Apply / Correction','Birth Certificate','Passport Application','Online Bill Pay','Form Fill-up','Result Check']},
  {icon:'📱',title:'Mobile Accessories',desc:'Genuine mobile accessories at best price.',price:'৳100 - ৳5000',list:['Charger & Cable','Earphones / Headphones','Phone Case & Cover','Screen Protector','Power Bank','Bluetooth Speaker']},
  {icon:'💻',title:'Computer Accessories',desc:'Premium computer parts and peripherals.',price:'৳200 - ৳20000',list:['Keyboard & Mouse','RAM / SSD / HDD','Monitor / Webcam','Printer & Toner','USB / Cables','Networking Items']},
  {icon:'📷',title:'Photo Studio',desc:'Professional photography & editing service.',price:'৳100 - ৳3000',list:['Passport Size Photo','Biometric Photo','Photo Editing','Wedding Photography','Event Coverage','Print Service']},
  {icon:'🏦',title:'Mobile Banking',desc:'All mobile banking transactions.',price:'Charge Apply',list:['bKash','Nagad','Rocket','Upay','Sure Cash','Cash In / Out']},
  {icon:'📋',title:'Job Circular',desc:'Latest job notifications & application help.',price:'Free Info',list:['Govt Job Circular','Private Job News','Application Form Fill','CV Writing','Job Preparation Tips','Result Notification']},
  {icon:'💡',title:'Tech Tips',desc:'Daily tech tutorials, tips and tricks.',price:'Free',list:['Mobile Tips','Computer Tips','Internet Tutorial','Software Reviews','Hardware Guide','Security Tips']},
  {icon:'🏞️',title:'Land Services',desc:'Land related online & documentation services.',price:'৳200 - ৳2000',list:['Land Mutation Apply','Khatian Check','Map Check','Online Tax Pay','Land Record','Documentation Help']}
];

// Render service cards
(function(){
  var grid=document.getElementById('servicesGrid');
  if(!grid)return;
  SERVICES.forEach(function(s,i){
    var c=document.createElement('div');
    c.className='service-card';
    c.onclick=function(){openModal(i)};
    c.innerHTML='<div class="service-icon">'+s.icon+'</div><h3>'+s.title+'</h3><p>'+s.desc+'</p><span class="service-link">View Details →</span>';
    grid.appendChild(c);
  });
})();

// Service modal
function openModal(i){
  var s=SERVICES[i];
  document.getElementById('mIcon').innerHTML=s.icon;
  document.getElementById('mTitle').innerHTML=s.title;
  document.getElementById('mDesc').innerHTML=s.desc;
  document.getElementById('mPrice').innerHTML=s.price;
  var ul=document.getElementById('mList');ul.innerHTML='';
  s.list.forEach(function(it){var li=document.createElement('li');li.innerHTML='✓ '+it;ul.appendChild(li)});
  document.getElementById('svcModal').classList.add('active');
}
function closeModal(){document.getElementById('svcModal').classList.remove('active')}

// ===== HERO SLIDER =====
(function(){
  var slides=document.querySelectorAll('.hero-slide');
  if(!slides.length)return;
  var dotsWrap=document.getElementById('heroDots');
  var idx=0;
  slides.forEach(function(_,i){
    var d=document.createElement('button');
    d.className='hero-dot'+(i===0?' active':'');
    d.onclick=function(){show(i)};
    dotsWrap.appendChild(d);
  });
  function show(n){
    idx=(n+slides.length)%slides.length;
    slides.forEach(function(s,i){s.classList.toggle('active',i===idx)});
    document.querySelectorAll('.hero-dot').forEach(function(d,i){d.classList.toggle('active',i===idx)});
  }
  window.heroNav=function(dir){show(idx+dir)};
  setInterval(function(){show(idx+1)},6000);
})();

// ===== GALLERY SLIDER =====
var gPos={};
function gNav(id,dir){
  var track=document.getElementById(id);
  if(!track)return;
  var slides=track.children.length;
  var perView=window.innerWidth<768?1:3;
  var max=Math.max(0,slides-perView);
  gPos[id]=(gPos[id]||0)+dir;
  if(gPos[id]<0)gPos[id]=max;
  if(gPos[id]>max)gPos[id]=0;
  track.style.transform='translateX(-'+(gPos[id]*(100/perView))+'%)';
}
// Auto-slide galleries
setInterval(function(){
  ['photoTrack','videoTrack'].forEach(function(id){if(document.getElementById(id))gNav(id,1)});
},5000);

// ===== SCROLL TO TOP =====
window.addEventListener('scroll',function(){
  var btn=document.getElementById('topBtn');
  if(btn)btn.classList.toggle('show',window.scrollY>400);
});

// ===== CHATBOT =====
function cbSend(){
  var inp=document.getElementById('cbInput');
  var msgs=document.getElementById('cbMsgs');
  var txt=inp.value.trim();
  if(!txt)return;
  var u=document.createElement('div');u.className='cb-msg cb-user';u.innerText=txt;msgs.appendChild(u);
  inp.value='';
  setTimeout(function(){
    var reply=cbReply(txt.toLowerCase());
    var b=document.createElement('div');b.className='cb-msg cb-bot';b.innerHTML=reply;msgs.appendChild(b);
    msgs.scrollTop=msgs.scrollHeight;
  },600);
  msgs.scrollTop=msgs.scrollHeight;
}
function cbReply(t){
  if(/hi|hello|hey|assalam/.test(t))return '👋 Hello! How can I help you today?';
  if(/price|cost|rate|charge/.test(t))return '💰 Our prices vary by service. Please share which service you need pricing for, or call <b>01822922882</b>.';
  if(/photo|studio/.test(t))return '📷 Photo Studio: Passport ৳100, Biometric ৳150, Editing ৳200+. Visit us or call 01822922882.';
  if(/bank|bkash|nagad|rocket/.test(t))return '🏦 We support bKash, Nagad, Rocket, Upay & Sure Cash transactions. Standard charges apply.';
  if(/job|circular/.test(t))return '📋 Visit our Blog → Job Circular section for latest govt & private job updates.';
  if(/contact|phone|address|call/.test(t))return '📞 Call: 01822922882<br/>💬 WhatsApp: wa.me/8801822922882<br/>🕒 Sat-Thu 9AM-9PM';
  if(/service/.test(t))return '🛠️ We offer 8 services: Online Services, Mobile/Computer Accessories, Photo Studio, Mobile Banking, Job Circular, Tech Tips, Land Services. Click any service card to know more.';
  if(/thanks|thank/.test(t))return '🙏 You are most welcome! Feel free to ask anything else.';
  return '🤔 I am not sure about that. Please call <b>01822922882</b> or <a href="https://wa.me/8801822922882" target="_blank" style="color:#2563eb">WhatsApp us</a> for direct help.';
}

// ===== FETCH RECENT POSTS FOR HOMEPAGE =====
(function() {
  var recentGrid = document.getElementById('recentPostsGrid');
  if (!recentGrid) return;

  fetch('/feeds/posts/default?alt=json&max-results=6')
    .then(function(response) { return response.json(); })
    .then(function(data) {
      if (!data.feed || !data.feed.entry) {
        recentGrid.innerHTML = '<p style="text-align:center;color:#64748b">No posts found.</p>';
        return;
      }

      var html = '';
      data.feed.entry.forEach(function(entry) {
        var title = entry.title.$t;
        var link = '#';
        entry.link.forEach(function(l) {
          if (l.rel === 'alternate') link = l.href;
        });
        var date = new Date(entry.published.$t);
        var formattedDate = date.toLocaleDateString('en-US', { year:'numeric', month:'short', day:'numeric' });
        var content = entry.summary ? entry.summary.$t.substring(0, 120) : 'Read more...';
        var thumbnail = '';

        // Extract thumbnail from media content or content
        if (entry.media$thumbnail) {
          thumbnail = entry.media$thumbnail.url;
        } else if (entry.content && entry.content.$t) {
          var imgMatch = entry.content.$t.match(/<img[^>]+src="([^">]+)"/);
          if (imgMatch) thumbnail = imgMatch[1];
        }
        if (!thumbnail) thumbnail = 'https://images.unsplash.com/photo-1518770660439-4636190af475?w=500';

        html += '<article class="blog-card">';
        html += '<a href="' + link + '"><img src="' + thumbnail + '" alt="' + title + '"></a>';
        html += '<div class="blog-body">';
        html += '<div class="blog-meta">' + formattedDate + '</div>';
        html += '<h3><a href="' + link + '">' + title + '</a></h3>';
        html += '<p style="color:#64748b;font-size:14px">' + escapeHtml(content) + '...</p>';
        html += '<a class="service-link" href="' + link + '">Read More →</a>';
        html += '</div></article>';
      });
      recentGrid.innerHTML = html;
    })
    .catch(function() {
      recentGrid.innerHTML = '<p style="text-align:center;color:#64748b">Failed to load recent posts.</p>';
    });
})();

// ===== FETCH NEWS FOR TICKER =====
(function() {
  var tickerTrack = document.getElementById('dynamicTicker');
  if (!tickerTrack) return;

  fetch('/feeds/posts/default?alt=json&max-results=10&category=News')
    .then(function(response) { return response.json(); })
    .then(function(data) {
      if (!data.feed || !data.feed.entry || data.feed.entry.length === 0) {
        tickerTrack.innerHTML = '<span>⚡ No news available. Check back soon!</span>';
        return;
      }

      var tickerHtml = '';
      data.feed.entry.forEach(function(entry) {
        var title = entry.title.$t;
        var link = '#';
        entry.link.forEach(function(l) {
          if (l.rel === 'alternate') link = l.href;
        });
        tickerHtml += '<a href="' + link + '" target="_top">🔴 ' + escapeHtml(title) + '</a>';
      });
      tickerTrack.innerHTML = tickerHtml;

      // Reset animation by cloning and restarting
      var newTrack = tickerTrack.cloneNode(true);
      tickerTrack.parentNode.replaceChild(newTrack, tickerTrack);
      newTrack.style.animation = 'none';
      newTrack.offsetHeight; // force reflow
      newTrack.style.animation = 'tickerScroll 30s linear infinite';
    })
    .catch(function() {
      tickerTrack.innerHTML = '<span>⚡ Welcome to Ayman IT Service!</span><span>📞 Call 01822922882</span><span>💬 WhatsApp: wa.me/8801822922882</span>';
    });
})();

// Helper function to escape HTML
function escapeHtml(text) {
  if (!text) return '';
  var div = document.createElement('div');
  div.appendChild(document.createTextNode(text));
  return div.innerHTML;
}

